import{_ as t,o as r,c as e,a6 as o}from"./chunks/framework.Dygbm21p.js";const u=JSON.parse('{"title":"Part 6 · 补充题库","description":"","frontmatter":{"part":6,"partTitle":"Part 6 · 补充题库","partColor":null},"headers":[],"relativePath":"parts/part-6.md","filePath":"parts/part-6.md"}'),n={name:"parts/part-6.md"};function a(i,s,p,d,l,c){return r(),e("div",null,[...s[0]||(s[0]=[o('<div class="part-hero" style="--part-color:#ef4444;"><h1 id="part-6-·-补充题库" tabindex="-1">Part 6 · 补充题库 <a class="header-anchor" href="#part-6-·-补充题库" aria-label="Permalink to &quot;Part 6 · 补充题库&quot;">​</a></h1><p class="part-desc">评测 · LangGraph · 口径备忘</p><span class="part-round">高频追问</span></div><div class="part-intro"><blockquote><p>覆盖简历亮点但未单独成题的知识点，以及高频追问</p></blockquote></div><hr><div class="question-card" id="q36"><h2 class="question-title"><span class="q-badge">Q36</span> RAG 评测 · 指标选型</h2><div class="q-meta"><strong>轮次</strong>：一面 · 难度：⭐⭐⭐ · 考察点：评测体系设计</div><div class="question-prompt"><strong>题目</strong>：你为什么用 Recall@5 而不是 nDCG 或 MRR？黄金集怎么构建的？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：科研问答核心是「找对段落」；Recall@5 直接衡量 Top-5 是否含答案段；nDCG 更重排序质量，MRR 只看第一个命中——我分阶段用 Recall 驱动召回优化，排序用重排+人工抽检补。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：有没有算 nDCG？ · 120 问怎么标注？ · 端到端怎么评？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;我选 Recall@5 是因为我们这个场景的第一优先级是<strong>召回</strong>——课题组同学问一个问题，系统能不能在 Top-5 里把真正包含答案的论文段落找出来。如果召回阶段就漏了，后面重排和生成再好也没用。</p><p>Recall@5 直接回答这个问题：正确答案有没有出现在前 5 个检索结果里。这对驱动 RAG pipeline 迭代非常直观——加 BM25、加重排、加改写，每一步都能在同一个指标上看跳了多少。</p><p>MRR（Mean Reciprocal Rank）更关注<strong>第一个</strong>正确结果排第几。我的场景里用户通常会看多个段落综合理解，不一定只依赖排名第一的片段，所以 MRR 不如 Recall@5 敏感。</p><p>nDCG 同时考虑召回和排序质量，理论上更全面，但它需要更细粒度的相关性标注（比如 0/1/2/3 多级相关度）。我早期资源有限，先做了二值标注——&#39;这个段落能不能支撑回答&#39;。Recall@5 够驱动前几个大优化。后期排序主要靠 Cross-Encoder 重排和引用校验通过率来补。</p><p>120 问黄金集的构建方式：从课题组真实提问里抽 80 问，我补充 40 个覆盖边界 case（跨论文、术语缩写、口语化提问）。每题标注 1-3 个&#39;金标准段落&#39;（论文 ID + 段落位置）。评测时只要 Top-5 命中任一金标准段落就算 Recall 成功。</p><p>如果现在要升级评测体系，我会在 Recall@5 稳定后加 nDCG@5 看排序质量，再加端到端指标——引用校验通过率、人工 1-5 分质量评分、平均校验轮次（简历里写的 1.3 轮）。三层指标分别对应检索、排序、生成。&quot;</p></div></details></div><hr><div class="question-card" id="q37"><h2 class="question-title"><span class="q-badge">Q37</span> LangGraph · 节点与条件边</h2><div class="q-meta"><strong>轮次</strong>：一面 · 难度：⭐⭐⭐⭐ · 考察点：LangGraph 落地细节</div><div class="question-prompt"><strong>题目</strong>：你的 RAG 用 LangGraph 编排，具体有几个节点？条件边怎么设计的？校验失败重试几次？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：主链路 5 节点：查询改写→混合检索→重排→生成→引用校验；校验失败走条件边回到改写或生成，最多 2 轮重试，避免死循环。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：State 里存什么？ · 和裸 FastAPI 链式调用区别？ · 为什么不用 ReAct？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;我的 LangGraph StateGraph 大概有 5 个核心节点，加 2 个条件分支。</p><p><strong>节点 1：查询改写</strong>。输入用户原始问题，输出改写后的检索 query（更论文化、补全术语）。状态里写入 <code>rewritten_query</code>。</p><p><strong>节点 2：混合检索</strong>。同时跑 dense（BGE-M3）+ BM25，合并候选池（大概 50-80 条），状态写入 <code>candidates</code>。</p><p><strong>节点 3：Cross-Encoder 重排</strong>。对候选 batch 推理，取 Top-5，状态写入 <code>reranked_docs</code> 和对应的父块上下文。</p><p><strong>节点 4：答案生成</strong>。把父块上下文 + 用户问题喂给 LLM（微调模型或 API），状态写入 <code>answer</code> 和 <code>citations</code>。</p><p><strong>节点 5：引用校验</strong>。拿生成结果里的引用反查原文——格式对不对、段落是否存在、语义是否支撑。输出 <code>validation_passed</code> 布尔值和失败原因。</p><p><strong>条件边设计</strong>：</p><ul><li>校验通过 → <code>END</code></li><li>校验失败且 <code>retry_count &lt; 2</code> → 回到节点 1 或节点 4（看失败类型：检索不对就改写 query 重检，生成胡说就重新生成）</li><li>校验失败且 <code>retry_count &gt;= 2</code> → 降级输出「信息不足」或返回当前最佳结果 + 警告</li></ul><p><code>retry_count</code> 存在 State 里，每走一次失败分支 +1。上限 2 次是为了控制延迟——每次重试大概多 1-2 秒，两轮已经是 P95 1.2s 预算里能接受的。</p><p>和裸 FastAPI 链式调用的区别：LangGraph 把<strong>分支逻辑显式化</strong>了——校验失败走哪条路、重试几次，在图上一眼能看出来。而且每个节点可以单独测、单独换实现。裸链式代码里这些 if-else 很快会变成 spaghetti。</p><p>选 LangGraph 而不是 ReAct 的原因：这条 pipeline 步骤和顺序是确定的，不需要 LLM 决定&#39;下一步该检索还是该生成&#39;。用 ReAct 反而让 LLM 有跳过校验或乱调工具的风险。&quot;</p></div></details></div><hr><div class="question-card" id="q38"><h2 class="question-title"><span class="q-badge">Q38</span> 诚实面 · 失败 case</h2><div class="q-meta"><strong>轮次</strong>：一面/三面 · 难度：⭐⭐⭐ · 考察点：真实性与复盘能力</div><div class="question-prompt"><strong>题目</strong>：你的 RAG 系统有哪些做失败了或效果不好的地方？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：三块没做好：PDF 双栏/公式解析、14% 引用校验仍失败、纯向量时代跨论文混淆；说明瓶颈往往在数据而非模型。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：为什么没换 MinerU？ · 86% 够上线吗？ · 如果重来第一步改什么？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;有三个印象深刻的失败或不够好。</p><p><strong>第一，PDF 解析</strong>。页眉页脚剔除对单栏论文还行，双栏论文经常把左右栏拼成一行，表格和公式基本丢失。我统计过一批失败 case，大概 30% 追溯到解析阶段。我知道 MinerU/Marker 更好，但当时优先把检索和生成链路跑通，解析升级一直排在 backlog——这也是我现在重做会优先改的地方。</p><p><strong>第二，引用校验 86% 通过率意味着 14% 仍然失败</strong>。失败分两类：一类是 PDF 解析丢信息，校验时找不到原文；另一类是 LLM 强行编造引用格式——看起来有 [论文标题, 段落X]，但段落内容根本不支撑结论。第二类靠微调和负样本压了一部分，但没完全消灭。</p><p><strong>第三，早期纯向量基线 0.51 那段时间，跨论文混淆非常严重</strong>。当时以为调大 embedding 模型或加 prompt 就能解决，结果发现根因是检索把多篇论文片段都召回来了——这是召回阶段的问题，不是生成阶段能救的。这个教训是：<strong>先定位失败在哪个环节，再动手</strong>，不然优化生成模型是在浪费时间。</p><p>还有一个&#39;没做&#39;的选择：我没上端到端 RLHF 或 DPO 做引用对齐，因为数据标注成本太高，1.8k SFT 数据已经是课题组能承受的极限。如果走工业界路线，可能会用 RAG + 轻量 reranker 微调，而不是继续堆大模型 SFT。</p><p>诚实说这些失败，比只讲 0.51→0.78 更让面试官相信你真的做过系统，而不是背数字。&quot;</p></div></details></div><hr><div class="question-card" id="q39"><h2 class="question-title"><span class="q-badge">Q39</span> 算法基础 · DSTG-Net</h2><div class="q-meta"><strong>轮次</strong>：一面（算法岗） · 难度：⭐⭐⭐⭐ · 考察点：简历算法项目深度</div><div class="question-prompt"><strong>题目</strong>：DSTG-Net 里 GCN 和 Transformer 双流怎么融合？为什么用自适应加权而不是简单相加？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：GCN 抓局部关节拓扑，Transformer 抓全局时序；自适应加权因不同关节/时间步两流贡献不同；加去相关损失防冗余和训练不稳。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：MPJPE 多少？ · 和 ST-GCN 区别？ · 消融实验怎么做？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;DSTG-Net 的核心是双流架构。</p><p><strong>GCN 分支</strong>在人体骨架图上做时空图卷积——关节是节点，骨骼是边，捕捉局部拓扑约束，比如手肘弯曲时手腕和肩膀的联动关系。</p><p><strong>Transformer 分支</strong>把所有关节序列拉成 token 序列，用 self-attention 捕捉长程时序依赖——比如走路周期里左右腿的交替模式。</p><p>两路特征维度对齐后，进入<strong>自适应融合模块</strong>：对每个时间步、每个关节学一个权重 α，输出是 α·F_gcn + (1-α)·F_transformer。不是全局一个 α，而是<strong>时空自适应</strong>的。</p><p>为什么不用简单相加？因为局部拓扑和全局时序的贡献在不同场景下不一样——短期预测（下一帧）GCN 更重要，长期预测（未来 1 秒）Transformer 的长程建模优势更明显。固定权重没法适应这种变化。消融实验里自适应加权在长期预测上比固定加权 MPJPE 低约 8%。</p><p>导师最初担心自适应模块增加参数导致训练不稳定。我的回应是加<strong>去相关损失</strong>——约束两流特征的互相关矩阵接近零，减少冗余表示。这既回应了稳定性担忧，又提升了效果。</p><p>实验在 Human3.6M、CMU-MoCap、3DPW 三个数据集上跑，和 ST-GCN、MSR-GCN 等对比。3DPW 短期 MPJPE 相对降 22.22%，长期最高降 15.10%。论文投 Pattern Recognition，目前在二审。</p><p>这个项目和 Agent 岗的关联是：做系统前先想清楚&#39;哪条路的信息更重要、怎么融合&#39;——和 RAG 里 dense+BM25 混合、GCN+Transformer 融合是同一类工程思维。&quot;</p></div></details></div><hr><div class="question-card" id="q40"><h2 class="question-title"><span class="q-badge">Q40</span> 简历深挖 · GenericAgent 你做了什么</h2><div class="q-meta"><strong>轮次</strong>：一面 · 难度：⭐⭐⭐⭐ · 考察点：项目真实性（高频追问）</div><div class="question-prompt"><strong>题目</strong>：GenericAgent 是你从零搭建的还是基于开源项目？你具体写了哪些代码？</div><div class="q-conclusion"><p>💡 <strong>15 秒结论</strong>：基于开源 ReAct Agent 框架深度二次开发：我负责 SiliconFlow/DeepSeek 接入、全链路跑通、生产级设计分析；叙事统一为「适配+分析+改进方案」而非含糊说「搭建」。</p></div><div class="q-followups"><p>🔁 <strong>追问方向</strong>：改了哪几个文件？ · 和原版 diff？ · 如果没开源你能从零写 ReAct 吗？</p></div><details class="answer-reveal"><summary>展开完整回答</summary><div class="answer-body"><p>&quot;这个问题我回答得比较诚实，分三层说。</p><p><strong>第一层，项目来源</strong>。GenericAgent 是基于一套开源的 ReAct Agent 框架——核心执行引擎、9 个原子工具、display_queue 事件总线、分层记忆的设计是框架原有的。我不是从零发明 ReAct 循环，而是在理解架构的基础上做深度二次开发和工程适配。</p><p><strong>第二层，我具体做了什么</strong>。三件事：</p><ol><li><strong>SiliconFlow API + DeepSeek 系列模型接入</strong>——写了调用协议适配、错误处理、和框架原有 5 类 Session 体系的对接，让框架能用国内 API 跑通。</li><li><strong>全链路跑通与验证</strong>——配置 mykey、跑通 CLI/Web 前端、用真实任务验证 ReAct 循环、工具调用、记忆读写。</li><li><strong>系统性架构分析</strong>——把 3K 行代码拆成接入层/执行引擎/工具层/记忆层，对比 Native Function Calling vs 文本协议、分析 code_run 安全边界、总结可改进点（human_confirmation、Token budget、pre-flight check）。</li></ol><p><strong>第三层，如果面试官问&#39;你改进了什么&#39;</strong>。我会说：我设计了 human_confirmation 工具的方案（Q14）、扩展了 code_run 三层安全（Q15）、提出了 display_queue 升级到 Redis 多端分发（Q34）。这些是<strong>设计方案</strong>，部分尚未全部落地到代码——但我能讲清楚为什么改、怎么改。</p><p><strong>为什么不只说&#39;搭建&#39;</strong>？因为面试官一旦追问源码细节，&#39;搭建&#39;和&#39;分析&#39;的差距会立刻暴露。统一口径是：<strong>在开源框架上做 API 适配、全链路验证和架构级分析与改进设计</strong>——这既真实，又保留技术深度。</p><p>如果让我从零写 ReAct 循环，我可以——Q31 就是我的设计答案，核心 while 循环大概 100 行，我在分析时已经逐行读过原版实现。&quot;</p></div></details></div><hr><div class="memo-card"><h2 id="📌-genericagent-口径备忘-非面试题-背诵前必读" tabindex="-1">📌 GenericAgent 口径备忘（非面试题，背诵前必读） <a class="header-anchor" href="#📌-genericagent-口径备忘-非面试题-背诵前必读" aria-label="Permalink to &quot;📌 GenericAgent 口径备忘（非面试题，背诵前必读）&quot;">​</a></h2><p>面试中统一用以下表述，避免「搭建」和「分析」口径打架：</p><table tabindex="0"><thead><tr><th>场景</th><th>推荐说法</th></tr></thead><tbody><tr><td>自我介绍（30 秒）</td><td>「基于 ReAct 开源框架做深度二次开发，完成 SiliconFlow 接入和全链路跑通，并系统分析了 LLM 接入层与分层记忆设计」</td></tr><tr><td>追问「你写的代码」</td><td>「API 适配与错误处理、配置与部署跑通；架构分析与改进方案设计」</td></tr><tr><td>追问「原创性」</td><td>「ReAct 循环和工具层是框架原有；我的价值在适配、验证、分析和可落地的改进设计」</td></tr><tr><td>不要说</td><td>「我从零搭建了一套 Agent 框架」（除非面试官明确问设计能力且你切到 Q31）</td></tr></tbody></table><hr><hr><blockquote><p>📌 共 40 问（原 35 问 + 新增 5 问）+ 开场话术 + GenericAgent 口径备忘。原有问答正文未改动，仅调整顺序并补充结论句与追问方向。面试中可根据实际情况调整细节和数字。</p></blockquote></div>',14)])])}const v=t(n,[["render",a]]);export{u as __pageData,v as default};
